import { GoogleGenAI, Type } from "@google/genai";
import { RAJBARI_DATA } from './constants';

// Initialize the Gemini AI with the provided API Key
const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const db = {
  /**
   * Gemini 3 API ব্যবহার করে এআই কল করা
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    tools?: any[]; 
    responseSchema?: any;
    responseMimeType?: string;
  }) => {
    try {
      const ai = getAIClient();

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: params.contents,
        config: {
          systemInstruction: params.systemInstruction || `আপনি রাজবাড়ী জেলার একজন ভার্চুয়াল অ্যাসিস্ট্যান্ট। 
          আপনার কাজ হলো রাজবাড়ী জেলার ট্রেন ট্র্যাকিং, ডাক্তার, হাসপাতাল এবং সাধারণ তথ্য প্রদান করা।
          - সর্বদা বাংলায় উত্তর দিন।
          - গুগল সার্চ ব্যবহার করে সর্বশেষ তথ্য দিন।`,
          tools: params.tools || [{ googleSearch: {} }],
          responseSchema: params.responseSchema,
          responseMimeType: params.responseMimeType,
          temperature: 0.1,
        }
      });

      return {
        text: response.text || "",
        groundingMetadata: response.candidates?.[0]?.groundingMetadata || null
      };
    } catch (error: any) {
      console.error("Gemini API Error:", error);
      throw new Error(error.message || "এআই সার্ভিসে সংযোগ করা সম্ভব হচ্ছে না।");
    }
  },

  getCategory: async (category: string) => {
    const defaultData = (RAJBARI_DATA as any)[category] || [];
    try {
      const response = await fetch(`/api/db?category=${category}`);
      if (response.ok) {
        const serverData = await response.json();
        if (serverData && serverData.length > 0) return serverData;
      }
    } catch (e) {
      console.warn("Using offline data.");
    }
    return defaultData;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Loader2, Sparkles, Trash2, AlertCircle, RefreshCcw, ShieldCheck, Globe } from 'lucide-react';
import { db } from '../db';

const SYSTEM_INSTRUCTION = `
আপনি হলেন "রাজবাড়ী জেলা তথ্য সহায়িকা – AI Chat Assistant"।
আপনার দায়িত্ব ও বৈশিষ্ট্য:
১. রাজবাড়ী জেলা সম্পর্কে সকল তথ্য প্রদান করা।
২. ভাষা: সর্বদা বাংলা ব্যবহার করবেন।
৩. টোন: বিনয়ী ও সম্মানজনক।
৪. ডেভেলপার: Sovrab Roy।
৫. গুগল সার্চ ব্যবহার করে তথ্য দিন এবং তথ্যের সূত্র উল্লেখ করুন।
`;

interface Message {
  role: 'user' | 'model';
  text: string;
  isError?: boolean;
  errorType?: string;
  sources?: any[];
}

const AIChat: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: 'স্বাগতম! আমি রাজবাড়ী জেলা তথ্য সহায়িকা। আপনাকে কিভাবে সাহায্য করতে পারি?' }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const handleSend = async (retryText?: string) => {
    const userMessage = retryText || input.trim();
    if (!userMessage || isTyping) return;

    if (!retryText) {
        setInput('');
        setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    }

    setIsTyping(true);

    try {
      const chatHistory = messages
        .filter(m => !m.isError)
        .map(m => ({
            role: m.role,
            parts: [{ text: m.text }]
        }));

      const data = await db.callAI({
        contents: [...chatHistory, { role: 'user', parts: [{ text: userMessage }] }],
        systemInstruction: SYSTEM_INSTRUCTION,
        tools: [{ googleSearch: {} }]
      });

      const responseText = data.text || "দুঃখিত, আমি এই মুহূর্তে উত্তর দিতে পারছি না।";
      const sources = data.groundingMetadata?.groundingChunks || [];

      setMessages(prev => [...prev, { 
        role: 'model', 
        text: responseText,
        sources: sources
      }]);
    } catch (error: any) {
      console.error("AI Error:", error);
      const errorMsg = error.message || "সার্ভারের সাথে সংযোগ করা যাচ্ছে না।";
      setMessages(prev => [...prev, { 
        role: 'model', 
        text: `${errorMsg}\nদয়া করে ইন্টারনেট কানেকশন চেক করুন।`, 
        isError: true, 
        errorType: 'network' 
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-180px)] animate-slide-up relative">
      <div className="px-6 py-4 flex items-center justify-between border-b border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 shadow-sm z-10">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-lg">
            <Sparkles className="w-5 h-5" />
          </div>
          <div>
            <h3 className="font-black text-slate-800 dark:text-white leading-none">রাজবাড়ী স্মার্ট সাপোর্ট</h3>
            <div className="flex items-center gap-1.5 mt-1">
              <div className="flex items-center gap-1 px-2 py-0.5 rounded-full text-[8px] font-black uppercase tracking-tighter bg-emerald-100 text-emerald-600">
                <ShieldCheck className="w-2.5 h-2.5" />
                Gemini 3 Active
              </div>
            </div>
          </div>
        </div>
        <button onClick={() => setMessages([{ role: 'model', text: 'স্বাগতম! আমি রাজবাড়ী জেলা তথ্য সহায়িকা। আপনাকে কিভাবে সাহায্য করতে পারি?' }])} className="p-3 text-slate-400 hover:text-rose-500 rounded-xl">
          <Trash2 className="w-5 h-5" />
        </button>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar p-6 space-y-6 bg-slate-50 dark:bg-slate-950">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex gap-3 max-w-[90%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-xl flex items-center justify-center shrink-0 ${msg.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-white dark:bg-slate-800 text-indigo-600 shadow-sm border border-slate-100 dark:border-slate-800'}`}>
                {msg.role === 'user' ? <User className="w-4 h-4" /> : <Bot className="w-4 h-4" />}
              </div>
              <div className="flex flex-col gap-2">
                <div className={`p-4 rounded-3xl text-sm leading-relaxed whitespace-pre-line shadow-sm border ${
                  msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none border-indigo-600 shadow-indigo-100' 
                  : msg.isError 
                    ? 'bg-rose-50 dark:bg-rose-950/30 text-rose-700 dark:text-rose-400 border-rose-200 dark:border-rose-900/50 rounded-tl-none'
                    : 'bg-white dark:bg-slate-900 text-slate-700 dark:text-slate-200 rounded-tl-none border-slate-100 dark:border-slate-800'
                }`}>
                  {msg.isError && <AlertCircle className="w-4 h-4 mb-2 inline-block mr-1" />}
                  {msg.text}

                  {msg.sources && msg.sources.length > 0 && (
                    <div className="mt-4 pt-3 border-t border-slate-200/50 dark:border-slate-700/50">
                      <p className="text-[9px] font-black uppercase tracking-widest text-slate-400 mb-2">তথ্যসূত্র (Google Search):</p>
                      <div className="flex flex-wrap gap-2">
                        {msg.sources.map((chunk: any, sidx: number) => (
                          chunk.web && (
                            <a 
                              key={sidx} 
                              href={chunk.web.uri} 
                              target="_blank" 
                              rel="noopener noreferrer"
                              className="flex items-center gap-1.5 text-[9px] font-bold text-indigo-600 dark:text-indigo-400 bg-indigo-50 dark:bg-indigo-900/30 px-2.5 py-1 rounded-lg border border-indigo-100 dark:border-indigo-800/50 hover:scale-105 transition-transform"
                            >
                              <Globe className="w-2.5 h-2.5" /> Source {sidx+1}
                            </a>
                          )
                        ))}
                      </div>
                    </div>
                  )}
                </div>
                {msg.isError && (
                  <button onClick={() => handleSend([...messages].reverse().find(m => m.role === 'user')?.text)} className="flex items-center gap-2 text-[10px] font-black text-indigo-600 bg-white dark:bg-slate-900 px-4 py-2 rounded-full shadow-sm border border-indigo-50 dark:border-indigo-900/50 self-start">
                    <RefreshCcw className="w-3 h-3" /> পুনরায় চেষ্টা
                  </button>
                )}
              </div>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start items-center gap-3">
            <div className="w-8 h-8 rounded-xl bg-white dark:bg-slate-800 flex items-center justify-center text-indigo-600 shadow-sm border border-slate-100 dark:border-slate-800"><Bot className="w-4 h-4" /></div>
            <div className="bg-white dark:bg-slate-900 px-4 py-3 rounded-2xl border border-slate-100 dark:border-slate-800 flex gap-1">
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.4s]"></div>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-6 bg-white dark:bg-slate-950 border-t border-slate-100 dark:border-slate-800">
        <div className="flex gap-3 bg-slate-50 dark:bg-slate-900 p-2 rounded-[2rem] border border-slate-200 dark:border-slate-800 focus-within:border-indigo-400 transition-all shadow-inner">
          <input 
            type="text" 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSend()}
            placeholder="রাজবাড়ী সম্পর্কে জিজ্ঞাসা করুন..." 
            className="flex-1 bg-transparent border-none focus:ring-0 text-sm px-4 text-slate-800 dark:text-white"
          />
          <button 
            onClick={() => handleSend()}
            disabled={!input.trim() || isTyping}
            className={`w-12 h-12 rounded-full flex items-center justify-center transition-all ${
              !input.trim() || isTyping ? 'bg-slate-200 text-slate-400' : 'bg-indigo-600 text-white shadow-lg'
            }`}
          >
            {isTyping ? <Loader2 className="w-5 h-5 animate-spin" /> : <Send className="w-5 h-5" />}
          </button>
        </div>
      </div>
    </div>
  );
};

export default AIChat;

import React, { useState, useEffect, useRef } from 'react';
import { Search, MapPin, Navigation, Loader2, Map as MapIcon, Crosshair, ShieldAlert, Building2, Info, Sparkles, Utensils, Hotel, Tent } from 'lucide-react';
import L from 'leaflet';
import { db } from '../db';
import { Type } from "@google/genai";

interface Place {
  id: string | number;
  name: string;
  category: 'hospital' | 'police' | 'emergency' | 'hotel' | 'restaurant' | 'landmark' | 'other';
  lat: number;
  lng: number;
  phone?: string;
  description?: string;
  isAI?: boolean;
}

const PLACES_DATA: Place[] = [
  { id: 1, name: 'রাজবাড়ী সদর হাসপাতাল', category: 'hospital', lat: 23.7635, lng: 89.6468, phone: '০৬৪১-৬৫১১১' },
  { id: 2, name: 'রাজবাড়ী সদর থানা', category: 'police', lat: 23.7588, lng: 89.6495, phone: '০১৭৬৯-০৫৮২১১' },
  { id: 3, name: 'রাজবাড়ী ফায়ার সার্ভিস', category: 'emergency', lat: 23.7542, lng: 89.6550, phone: '০১৭৩০-০০২৪৪৫' },
  { id: 4, name: 'পাংশা মডেল থানা', category: 'police', lat: 23.7925, lng: 89.4244, phone: '০১৩২০-১৫১৫১২' },
  { id: 5, name: 'বালিয়াকান্দি থানা', category: 'police', lat: 23.6265, lng: 89.5495, phone: '০১৩২০-১৫১৫৩৪' },
  { id: 6, name: 'গোয়ালন্দ ঘাট থানা', category: 'police', lat: 23.7315, lng: 89.7615, phone: '০১৩২০-১৫১৫৭৮' },
  { id: 7, name: 'সেবা ক্লিনিক রাজবাড়ী', category: 'hospital', lat: 23.7570, lng: 89.6450, phone: '০১৭২১-৫৫৮৮৯৯' },
];

const MapView: React.FC = () => {
  const [query, setQuery] = useState('');
  const [mapInstance, setMapInstance] = useState<L.Map | null>(null);
  const [loading, setLoading] = useState(true);
  const [isSearching, setIsSearching] = useState(false);
  const [userLocation, setUserLocation] = useState<[number, number] | null>(null);
  const [filteredPlaces, setFilteredPlaces] = useState<Place[]>(PLACES_DATA);
  const [aiPlaces, setAiPlaces] = useState<Place[]>([]);

  const mapRef = useRef<HTMLDivElement>(null);
  const markersLayerRef = useRef<L.LayerGroup | null>(null);

  const getCategoryName = (cat: string) => {
    const names: Record<string, string> = { 
      hospital: 'হাসপাল', 
      police: 'থানা', 
      emergency: 'জরুরি সেবা',
      hotel: 'হোটেল/আবাসন',
      restaurant: 'রেস্টুরেন্ট',
      landmark: 'দর্শনীয় স্থান',
      other: 'অন্যান্য'
    };
    return names[cat] || cat;
  };

  const getIconForCategory = (cat: string) => {
    const icons: Record<string, string> = {
      hospital: 'https://cdn-icons-png.flaticon.com/512/2966/2966327.png',
      police: 'https://cdn-icons-png.flaticon.com/512/3595/3595514.png',
      emergency: 'https://cdn-icons-png.flaticon.com/512/564/564793.png',
      hotel: 'https://cdn-icons-png.flaticon.com/512/2983/2983973.png',
      restaurant: 'https://cdn-icons-png.flaticon.com/512/3448/3448609.png',
      landmark: 'https://cdn-icons-png.flaticon.com/512/2451/2451551.png'
    };
    return icons[cat] || 'https://cdn-icons-png.flaticon.com/512/684/684908.png';
  };

  useEffect(() => {
    if (!mapRef.current || mapInstance) return;
    const rajbariCenter: [number, number] = [23.7571, 89.6508];
    const map = L.map(mapRef.current, { center: rajbariCenter, zoom: 13, zoomControl: false });
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png').addTo(map);
    const markersLayer = L.layerGroup().addTo(map);
    markersLayerRef.current = markersLayer;
    setMapInstance(map);
    setLoading(false);

    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition((pos) => {
        const loc: [number, number] = [pos.coords.latitude, pos.coords.longitude];
        setUserLocation(loc);
        L.circleMarker(loc, { radius: 8, fillColor: "#4f46e5", color: "#fff", weight: 3, opacity: 1, fillOpacity: 1 }).addTo(map).bindPopup("আপনি এখানে আছেন");
        map.setView(loc, 14);
      }, () => console.warn("Location access denied."));
    }
    return () => { map.remove(); };
  }, []);

  useEffect(() => {
    if (!mapInstance || !markersLayerRef.current) return;
    markersLayerRef.current.clearLayers();
    const allPlaces = [...filteredPlaces, ...aiPlaces];
    const bounds: L.LatLngExpression[] = [];

    allPlaces.forEach(place => {
      const icon = L.icon({
        iconUrl: getIconForCategory(place.category),
        iconSize: [36, 36],
        iconAnchor: [18, 18],
        popupAnchor: [0, -18]
      });

      const marker = L.marker([place.lat, place.lng], { icon })
        .bindPopup(`
          <div style="padding: 8px; font-family: 'Hind Siliguri', sans-serif; text-align: center; min-width: 140px;">
            <div style="display: flex; align-items: center; justify-content: center; gap: 4px; margin-bottom: 4px;">
               ${place.isAI ? '<span style="background: #eff6ff; color: #3b82f6; font-size: 8px; font-weight: 800; padding: 2px 6px; border-radius: 4px;">AI SEARCH</span>' : ''}
               <h3 style="font-weight: 700; margin: 0; font-size: 14px; color: #1e293b;">${place.name}</h3>
            </div>
            <p style="font-size: 11px; color: #64748b;">${getCategoryName(place.category)}</p>
          </div>
        `);
      markersLayerRef.current?.addLayer(marker);
      bounds.push([place.lat, place.lng]);
    });

    if (bounds.length > 0 && mapInstance) {
      mapInstance.fitBounds(L.latLngBounds(bounds), { padding: [50, 50], maxZoom: 16 });
    }
  }, [mapInstance, filteredPlaces, aiPlaces]);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    const searchVal = query.toLowerCase().trim();
    if (!searchVal) return;

    setIsSearching(true);
    try {
      const response = await db.callAI({
        contents: [{ parts: [{ text: `Find precisely the coordinates of "${searchVal}" in Rajbari District, Bangladesh. Use Google Search to find exact latitude and longitude.` }] }],
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              lat: { type: Type.NUMBER },
              lng: { type: Type.NUMBER },
              category: { type: Type.STRING, description: "Category of the place: hotel, restaurant, landmark, hospital, police, other" }
            },
            required: ['name', 'lat', 'lng', 'category']
          }
        }
      });

      const results = JSON.parse(response.text || '[]');
      setAiPlaces(results.map((r: any, idx: number) => ({ ...r, id: `ai-${idx}`, isAI: true })));
    } catch (error) {
      console.error("Map Search Error:", error);
      alert("ম্যাপে এই স্থানটি খুঁজে পাওয়া যায়নি।");
    } finally {
      setIsSearching(false);
    }
  };

  return (
    <div className="p-6 animate-slide-up pb-32">
      <div className="bg-indigo-600 rounded-[2.5rem] p-8 text-white mb-8 relative overflow-hidden shadow-2xl">
        <h2 className="text-3xl font-bold flex items-center gap-3">
          <MapIcon className="w-8 h-8" /> ম্যাপ এক্সপ্লোরার
        </h2>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-[3rem] overflow-hidden premium-shadow border border-slate-100 dark:border-slate-800 mb-8 h-[450px] relative z-10">
        {(loading || isSearching) && (
          <div className="absolute inset-0 flex items-center justify-center bg-slate-50/80 dark:bg-slate-950/80 z-20">
            <Loader2 className="w-12 h-12 text-indigo-600 animate-spin" />
          </div>
        )}
        <div ref={mapRef} className="w-full h-full" />
      </div>

      <form onSubmit={handleSearch} className="mb-8">
        <div className="relative group">
          <Search className="absolute left-6 top-1/2 -translate-y-1/2 w-6 h-6 text-indigo-300" />
          <input 
            type="text" 
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="ম্যাপে খুঁজুন (যেমন: বাজার, স্কুল...)" 
            className="w-full bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-[2rem] py-5 pl-16 pr-8 text-slate-800 dark:text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all shadow-lg font-medium"
          />
        </div>
      </form>

      <div className="grid gap-4">
        {[...filteredPlaces, ...aiPlaces].map(place => (
          <div key={place.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2rem] border border-slate-50 dark:border-slate-800 flex items-center justify-between group transition-all hover:border-indigo-200">
            <div className="flex gap-4">
              <div className="p-4 rounded-2xl bg-indigo-50 dark:bg-indigo-950/30 text-indigo-600">
                <MapPin className="w-5 h-5" />
              </div>
              <div>
                <div className="flex items-center gap-2">
                  <h4 className="font-bold text-slate-800 dark:text-white text-lg">{place.name}</h4>
                  {place.isAI && <Sparkles className="w-3 h-3 text-amber-500" />}
                </div>
                <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{getCategoryName(place.category)}</p>
              </div>
            </div>
            <button onClick={() => mapInstance?.setView([place.lat, place.lng], 16)} className="p-3 bg-slate-50 dark:bg-slate-800 rounded-xl text-slate-400 hover:text-indigo-600 active:scale-90 transition-all">
              <Navigation className="w-5 h-5" />
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

