import React, { useState, useEffect } from 'react';
import { 
  Phone, 
  MapPin, 
  Clock as ClockIcon, 
  Loader2, 
  TrainFront,
  X,
  Radar,
  Sparkles,
  History,
  Info,
  Globe,
  RefreshCw,
  ShoppingBasket,
  ArrowUpRight,
  ArrowDownRight,
  Megaphone,
  AlertCircle,
  Briefcase,
  ExternalLink,
  Calendar
} from 'lucide-react';
import { Category, Train, AIInference } from '../types';
import { db } from '../db';
import { Type } from "@google/genai";

interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [aiInference, setAiInference] = useState<AIInference & { likelyCurrentStation?: string, sources?: any[], rawText?: string }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: [],
    rawText: ''
  });
  const [isInferring, setIsInferring] = useState(false);
  const [liveInfo, setLiveInfo] = useState<{currentStation: string, progress: number, status: string, nextStation?: string, stationIndex: number, isOffDay?: boolean, lastUpdated?: string} | null>(null);

  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      setCurrentTime(now);
      if (selectedTrain) {
        setLiveInfo(calculateLiveLocation(selectedTrain, aiInference));
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [selectedTrain, aiInference]);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      const items = await db.getCategory(category);
      setData(items);
      if (category === 'prayer') await fetchLivePrayerTimes();
      setLoading(false);
    };
    fetchData();
  }, [category]);

  const updateMarketPriceAI = async () => {
    setIsInferring(true);
    try {
      const response = await db.callAI({
        contents: [{ parts: [{ text: "Fetch current market prices for essential commodities (Rice, Pulse, Oil, Onion, Potato, Chicken, Egg) in Rajbari, Bangladesh. Provide data in JSON format." }] }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              unit: { type: Type.STRING },
              priceRange: { type: Type.STRING },
              trend: { type: Type.STRING, description: "up, down, or stable" }
            },
            required: ['name', 'unit', 'priceRange', 'trend']
          }
        }
      });
      const aiPrices = JSON.parse(response.text || '[]');
      if (aiPrices.length > 0) {
        setData(aiPrices.map((p: any, i: number) => ({ ...p, id: `ai-m-${i}`, isAI: true })));
      }
    } catch (e) {
      console.error("Market AI Error:", e);
    } finally {
      setIsInferring(false);
    }
  };

  const runAIInference = async (train: Train) => {
    setIsInferring(true);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'সার্চ করা হচ্ছে...', isAI: true, sources: [] });

    try {
      const prompt = `Find live location/status of train "${train.name} (${train.id})" in Bangladesh. Route: ${train.detailedRoute}. Current Time: ${currentTime.toLocaleTimeString('bn-BD')}.`;
      const response = await db.callAI({ contents: [{ parts: [{ text: prompt }] }] });
      const text = response.text || '';
      const sources = response.groundingMetadata?.groundingChunks || [];
      setAiInference({ delayMinutes: 0, confidence: 0.8, reason: text, isAI: true, sources, rawText: text });
    } catch (e) {
      setAiInference({ delayMinutes: 0, confidence: 0, reason: 'ত্রুটি হয়েছে।', isAI: false, sources: [] });
    } finally { setIsInferring(false); }
  };

  const calculateLiveLocation = (train: Train, inference: AIInference & { likelyCurrentStation?: string }) => {
    const stations = train.detailedRoute?.split(',').map(s => s.trim()) || [];
    if (stations.length === 0) return null;
    const idx = Math.min(Math.max(0, 0), stations.length - 1); // Logic fallback
    return { currentStation: stations[idx], progress: 10, status: 'শিডিউল অনুযায়ী চলছে', stationIndex: idx };
  };

  const fetchLivePrayerTimes = async () => {
    try {
      const res = await fetch('https://api.aladhan.com/v1/timingsByCity?city=Rajbari&country=Bangladesh&method=1');
      const json = await res.json();
      if (json.code === 200) {
        const t = json.data.timings;
        setData([
          { name: 'ফজর', time: t.Fajr, icon: '🌅' },
          { name: 'যোহর', time: t.Dhuhr, icon: '☀️' },
          { name: 'আসর', time: t.Asr, icon: '🌤️' },
          { name: 'মাগরিব', time: t.Maghrib, icon: '🌇' },
          { name: 'এশা', time: t.Isha, icon: '🌙' },
        ]);
      }
    } catch (e) { }
  };

  const renderItem = (item: any) => {
    switch (category) {
      case 'trains':
