      case 'jobs':
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-6 group">
            <div className="flex items-center gap-4 mb-5">
               <div className="p-4 bg-purple-50 dark:bg-purple-900/20 text-purple-600 rounded-2xl shadow-sm"><Briefcase className="w-6 h-6" /></div>
               <div>
                  <h4 className="font-bold text-slate-800 dark:text-white text-lg leading-tight group-hover:text-indigo-600 transition-colors">{item.title}</h4>
                  <p className="text-xs text-slate-400 font-bold uppercase mt-0.5">{item.org}</p>
               </div>
            </div>
            <div className="grid grid-cols-2 gap-3 mb-6">
               <div className="bg-slate-50 dark:bg-slate-800/50 p-3 rounded-xl">
                  <p className="text-[8px] text-slate-400 font-bold uppercase mb-1">যোগ্যতা</p>
                  <p className="text-[11px] font-black dark:text-white">{item.eligibility}</p>
               </div>
               <div className="bg-slate-50 dark:bg-slate-800/50 p-3 rounded-xl">
                  <p className="text-[8px] text-slate-400 font-bold uppercase mb-1">শেষ তারিখ</p>
                  <p className="text-[11px] font-black text-rose-500">{item.deadline}</p>
               </div>
            </div>
            <a href={item.link} target="_blank" rel="noopener noreferrer" className="w-full bg-slate-900 dark:bg-indigo-600 text-white py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 shadow-xl hover:scale-[1.02] active:scale-95 transition-all">
              বিস্তারিত ও আবেদন <ExternalLink className="w-4 h-4" />
            </a>
          </div>
        );
      case 'prayer':
        return (
          <div key={item.name} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-4 flex items-center justify-between group transition-all hover:bg-violet-50 dark:hover:bg-violet-950/20">
            <div className="flex items-center gap-5">
               <div className="text-3xl grayscale group-hover:grayscale-0 transition-all transform group-hover:scale-110">{item.icon}</div>
               <div>
                  <h4 className="font-bold text-slate-800 dark:text-white text-xl">{item.name}</h4>
                  <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">ওয়াক্ত শুরু</p>
               </div>
            </div>
            <div className="bg-slate-50 dark:bg-slate-800 px-6 py-3 rounded-2xl border border-slate-100 dark:border-slate-700 shadow-inner">
               <p className="text-2xl font-black text-indigo-600 tracking-tighter">{item.time}</p>
            </div>
          </div>
        );
      default:
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-4 flex items-center justify-between group transition-all hover:-translate-y-1">
            <div className="flex items-center gap-4">
               <div className="p-3 bg-slate-50 dark:bg-slate-800 rounded-xl text-indigo-600"><Info className="w-5 h-5" /></div>
