            <div className="flex items-center gap-4 mb-8">
              <div className="bg-indigo-600 p-4 rounded-2xl text-white shadow-xl">
                {isInferring ? <Loader2 className="w-6 h-6 animate-spin" /> : <TrainFront className="w-6 h-6" />}
              </div>
              <div>
                <h4 className="text-xl font-black dark:text-white uppercase tracking-tighter">{selectedTrain.name}</h4>
                <div className="flex items-center gap-2">
                  <div className={`w-2 h-2 rounded-full animate-ping ${isInferring ? 'bg-amber-500' : 'bg-emerald-500'}`}></div>
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{isInferring ? 'ইন্টারনেট সার্চ করা হচ্ছে...' : 'লাইভ ট্র্যাকিং সক্রিয়'}</span>
                </div>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto no-scrollbar pr-1">
              <div className="space-y-6">
                <div className="p-6 rounded-[2.5rem] border-2 bg-indigo-50 dark:bg-indigo-900/10 border-indigo-100 dark:border-indigo-900/30">
                  <div className="flex justify-between items-center mb-3">
                     <p className="text-[9px] font-black uppercase tracking-widest text-indigo-500 flex items-center gap-1.5"><History className="w-3.5 h-3.5" /> এআই স্মার্ট ড্যাশবোর্ড</p>
                  </div>
                  <h3 className="text-xl font-black dark:text-white leading-tight mb-4">{aiInference.reason || 'লোডিং...'}</h3>
                  {aiInference.sources && aiInference.sources.length > 0 && (
                        <div className="flex flex-wrap gap-2 pt-2 border-t border-slate-200/50">
                          {aiInference.sources.map((chunk: any, sidx: number) => (
                            chunk.web && (
                              <a key={sidx} href={chunk.web.uri} target="_blank" rel="noopener noreferrer" className="flex items-center gap-1 text-[8px] font-black text-indigo-600 bg-white dark:bg-slate-800 px-2 py-1 rounded-md border border-indigo-100 hover:bg-indigo-50">
                                <Globe className="w-2 h-2" /> Source {sidx+1}
                              </a>
                            )
                          ))}
                        </div>
                      )}
                </div>
              </div>
            </div>
            <button onClick={() => setSelectedTrain(null)} className="mt-6 w-full bg-slate-900 text-white py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-2xl active:scale-95 transition-all">বন্ধ করুন</button>
          </div>
        </div>
      )}

      {loading ? (
        <div className="space-y-6">{[1,2,3,4].map(i => <div key={i} className="h-40 shimmer rounded-[2.5rem]" />)}</div>
      ) : (
        <div className="space-y-4 animate-slide-up">
           {category === 'market_price' && isInferring && (
             <div className="bg-lime-50 dark:bg-lime-900/10 p-8 rounded-[2.5rem] border border-lime-100 dark:border-lime-900/30 text-center mb-6">
                <Loader2 className="w-10 h-10 text-lime-600 animate-spin mx-auto mb-4" />
                <p className="text-sm font-black text-lime-700 dark:text-lime-400 uppercase tracking-widest">সর্বশেষ বাজারদর খোঁজা হচ্ছে...</p>
             </div>
           )}
           {data.map(item => renderItem(item))}
        </div>
      )}
    </div>
  );
};

export default CategoryView;

