                <p className="text-[10px] font-black uppercase text-slate-400 mt-1 tracking-widest">{item.type}</p>
              </div>
            </div>
            <div className="text-right">
               <p className="text-sm font-black text-orange-600 tracking-tighter">{item.date}</p>
            </div>
          </div>
        );
      case 'market_price':
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 flex items-center justify-between mb-4 group transition-all hover:border-lime-400">
