            <div className="bg-slate-50 dark:bg-slate-800 px-6 py-3 rounded-2xl border border-slate-100 dark:border-slate-700 shadow-inner">
               <p className="text-2xl font-black text-indigo-600 tracking-tighter">{item.time}</p>
            </div>
          </div>
        );
      case 'trains':
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-6 group transition-all hover:-translate-y-1">
            <div className="flex items-center gap-4 mb-4">
              <div className="w-12 h-12 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl flex items-center justify-center"><TrainFront className="w-6 h-6" /></div>
              <div className="flex-1">
                <h4 className="font-bold text-slate-800 dark:text-white text-lg">{item.name}</h4>
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.route}</p>
              </div>
            </div>
            <div className="grid grid-cols-2 gap-4 mb-5">
              <div className="bg-slate-50 dark:bg-slate-800/50 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 text-center">
                <p className="text-[8px] text-slate-400 font-bold uppercase mb-1">আগমন</p>
                <p className="text-xl font-black dark:text-white tracking-tighter">{item.arrival || '--'}</p>
              </div>
              <div className="bg-slate-50 dark:bg-slate-800/50 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 text-center">
                <p className="text-[8px] text-slate-400 font-bold uppercase mb-1">প্রস্থান</p>
                <p className="text-xl font-black text-indigo-600 tracking-tighter">{item.departure}</p>
              </div>
            </div>
          </div>
        );
      default:
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-4 flex items-center justify-between group transition-all hover:-translate-y-1">
            <div className="flex items-center gap-4">
               <div className="p-3 bg-slate-50 dark:bg-slate-800 rounded-xl text-indigo-600"><Info className="w-5 h-5" /></div>
               <div><h4 className="font-bold dark:text-white text-lg">{item.name || item.title}</h4><p className="text-xs text-slate-400 font-bold">{item.address || item.details || item.number || item.mobile}</p></div>
            </div>
            {(item.mobile || item.number) && <a href={`tel:${item.mobile || item.number}`} className="p-4 bg-indigo-50 dark:bg-slate-800 rounded-2xl text-indigo-600 active:scale-90 transition-all"><Phone className="w-6 h-6" /></a>}
          </div>
        );
    }
  };

  return (
    <div className="px-6 py-6 pb-32">
      <div className="flex items-center justify-between mb-8 px-2">
         <div className="flex flex-col">
           <h3 className="text-2xl font-black text-slate-800 dark:text-white tracking-tighter uppercase">
             {category === 'market_price' ? 'লাইভ বাজারদর' : category === 'prayer' ? 'নামাজের সময়' : category === 'notices' ? 'সর্বশেষ নোটিশ' : category === 'jobs' ? 'চাকরি বিজ্ঞপ্তি' : category === 'holidays' ? 'ছুটির তালিকা' : 'তালিকা'}
           </h3>
           <p className="text-[10px] font-black text-indigo-500 uppercase tracking-[0.4em]">District Information</p>
         </div>
         {(['market_price', 'notices', 'jobs'].includes(category)) && (
           <button onClick={updateWithAI} disabled={isInferring} className={`p-4 bg-indigo-600 text-white rounded-2xl shadow-xl active:scale-90 transition-all ${isInferring ? 'animate-spin opacity-50' : ''}`}>
             <RefreshCw className="w-5 h-5" />
           </button>
         )}
         {category === 'prayer' && (
           <button onClick={fetchLivePrayerTimes} className="p-4 bg-violet-600 text-white rounded-2xl shadow-xl active:scale-90 transition-all">
             <RefreshCw className="w-5 h-5" />
           </button>
         )}
      </div>

      {loading ? (
        <div className="space-y-6">{[1,2,3,4].map(i => <div key={i} className="h-40 shimmer rounded-[2.5rem]" />)}</div>
      ) : (
        <div className="space-y-4 animate-slide-up">
           {isInferring && (
             <div className="bg-indigo-50 dark:bg-indigo-900/10 p-8 rounded-[2.5rem] border border-indigo-100 dark:border-indigo-900/30 text-center mb-6">
                <Loader2 className="w-10 h-10 text-indigo-600 animate-spin mx-auto mb-4" />
                <p className="text-sm font-black text-indigo-700 dark:text-indigo-400 uppercase tracking-widest">সর্বশেষ তথ্য খোঁজা হচ্ছে...</p>
             </div>
           )}
           {data.map(item => renderItem(item))}
        </div>
      )}
    </div>
  );
};

