    setIsInferring(true);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'সার্চ করা হচ্ছে...', isAI: true, sources: [] });
    try {
      const response = await db.callAI({
        contents: [{ parts: [{ text: `Find live location or latest status of train "${train.name} (${train.id})" in Bangladesh. Current route: ${train.detailedRoute}. Tell me if it's on time or delayed.` }] }],
        tools: [{ googleSearch: {} }]
      });
      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0.9, 
        reason: response.text || "দুঃখিত, কোনো তথ্য পাওয়া যায়নি।", 
        isAI: true,
        sources: response.groundingMetadata?.groundingChunks || []
      });
    } catch (e) {
      setAiInference({ delayMinutes: 0, confidence: 0, reason: 'সার্ভার ত্রুটি।', isAI: false });
