                <p className="text-xl font-black text-indigo-600 tracking-tighter">{item.departure}</p>
              </div>
            </div>
            <button onClick={() => { setSelectedTrain(item); trackTrainAI(item); }} className="w-full bg-indigo-600 text-white py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 shadow-xl hover:bg-indigo-700 active:scale-95 transition-all">
              <Radar className="w-4 h-4" /> লাইভ রিপোর্ট (AI)
            </button>
          </div>
        );
      case 'holidays':
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2rem] border border-slate-50 dark:border-slate-800 mb-4 flex items-center justify-between group transition-all hover:bg-orange-50 dark:hover:bg-orange-950/20">
            <div className="flex gap-4 items-center">
              <div className="w-12 h-12 rounded-2xl bg-orange-100 dark:bg-orange-900/30 text-orange-600 flex items-center justify-center">
                <Calendar className="w-6 h-6" />
              </div>
              <div>
                <h4 className="font-bold text-slate-800 dark:text-white leading-tight">{item.name}</h4>
                <p className="text-[10px] font-black uppercase text-slate-400 mt-1 tracking-widest">{item.type}</p>
              </div>
            </div>
            <div className="text-right">
               <p className="text-sm font-black text-orange-600 tracking-tighter">{item.date}</p>
            </div>
          </div>
        );
      case 'market_price':
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 flex items-center justify-between mb-4 group">
             <div className="flex items-center gap-4">
                <div className="p-4 bg-lime-50 dark:bg-lime-900/20 text-lime-600 rounded-2xl group-hover:scale-110 transition-transform"><ShoppingBasket className="w-6 h-6" /></div>
                <div>
                   <h4 className="font-bold dark:text-white text-lg">{item.name}</h4>
                   <p className="text-xs text-slate-400 font-bold uppercase">{item.unit}</p>
                </div>
             </div>
             <div className="text-right">
                <div className="flex items-center justify-end gap-1.5 mb-1">
                   {item.isAI && <Sparkles className="w-3 h-3 text-amber-500" />}
                   <p className="text-xl font-black text-indigo-600 tracking-tighter">{item.priceRange}</p>
                </div>
                <div className={`flex items-center justify-end gap-1 text-[8px] font-black uppercase ${item.trend === 'up' ? 'text-rose-500' : item.trend === 'down' ? 'text-emerald-500' : 'text-slate-400'}`}>
                   {item.trend === 'up' ? 'বাড়তি' : item.trend === 'down' ? 'কমছে' : 'স্থিতিশীল'}
                </div>
             </div>
          </div>
        );
      case 'notices':
        return (
          <div key={item.id} className={`bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] border ${item.priority === 'high' ? 'border-rose-200' : 'border-slate-50'} mb-6 relative overflow-hidden shadow-sm`}>
            {item.priority === 'high' && <div className="absolute top-0 right-0 bg-rose-500 text-white text-[8px] font-black uppercase px-4 py-1 rounded-bl-xl tracking-widest">Emergency</div>}
            <div className="flex gap-4 mb-4">
               <div className={`p-4 rounded-2xl ${item.priority === 'high' ? 'bg-rose-50 text-rose-600' : 'bg-orange-50 text-orange-600'}`}>
                 <Megaphone className="w-6 h-6" />
               </div>
               <div>
                  <h4 className="font-bold text-slate-800 dark:text-white text-lg leading-tight">{item.title}</h4>
                  <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">{item.date}</p>
               </div>
            </div>
            <p className="text-sm text-slate-600 dark:text-slate-400 italic bg-slate-50 dark:bg-slate-800/50 p-4 rounded-2xl">
