          </div>
        );
      case 'jobs':
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-6">
            <div className="flex items-center gap-4 mb-5">
               <div className="p-4 bg-purple-50 text-purple-600 rounded-2xl"><Briefcase className="w-6 h-6" /></div>
               <div className="flex-1">
                  <h4 className="font-bold text-slate-800 dark:text-white text-lg">{item.title}</h4>
                  <p className="text-xs text-slate-400 font-bold uppercase">{item.org}</p>
               </div>
            </div>
