                  <p className="text-[10px] font-black text-rose-500">{item.deadline}</p>
               </div>
            </div>
            <a href={item.link} target="_blank" rel="noopener noreferrer" className="w-full bg-indigo-600 text-white py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 shadow-xl">
              বিস্তারিত ও আবেদন <ExternalLink className="w-4 h-4" />
