        );
      case 'prayer':
        return (
          <div key={item.name} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-4 flex items-center justify-between group transition-all hover:bg-violet-50 dark:hover:bg-violet-950/20">
            <div className="flex items-center gap-5">
               <div className="text-3xl grayscale group-hover:grayscale-0 transition-all transform group-hover:scale-110">{item.icon}</div>
               <div>
                  <h4 className="font-bold text-slate-800 dark:text-white text-xl">{item.name}</h4>
                  <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">ওয়াক্ত শুরু</p>
