           <p className="text-[10px] font-black text-indigo-500 uppercase tracking-[0.4em]">District Portal</p>
         </div>
         {(['market_price', 'notices', 'jobs'].includes(category)) && (
           <button onClick={updateWithAI} disabled={isInferring} className={`p-4 bg-indigo-600 text-white rounded-2xl shadow-xl active:scale-90 transition-all ${isInferring ? 'animate-spin opacity-50' : ''}`}>
             <RefreshCw className="w-5 h-5" />
           </button>
         )}
         {category === 'prayer' && (
           <button onClick={fetchLivePrayerTimes} className="p-4 bg-violet-600 text-white rounded-2xl shadow-xl active:scale-90 transition-all">
             <RefreshCw className="w-5 h-5" />
           </button>
         )}
      </div>

      {selectedTrain && (
        <div className="fixed inset-0 z-[200] bg-slate-950/90 backdrop-blur-xl flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 w-full max-w-lg rounded-[3rem] p-6 shadow-3xl flex flex-col max-h-[90vh] animate-slide-up relative border border-white/10">
            <button onClick={() => setSelectedTrain(null)} className="absolute right-6 top-6 p-3 bg-slate-100 dark:bg-slate-800 rounded-2xl text-slate-500 z-10"><X className="w-6 h-6" /></button>
            <div className="flex items-center gap-4 mb-8">
              <div className="bg-indigo-600 p-4 rounded-2xl text-white shadow-xl">
                {isInferring ? <Loader2 className="w-6 h-6 animate-spin" /> : <TrainFront className="w-6 h-6" />}
              </div>
              <div>
                <h4 className="text-xl font-black dark:text-white uppercase tracking-tighter">{selectedTrain.name}</h4>
                <div className="flex items-center gap-2">
                  <div className={`w-2 h-2 rounded-full animate-ping ${isInferring ? 'bg-amber-500' : 'bg-emerald-500'}`}></div>
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{isInferring ? 'ইন্টারনেট সার্চ করা হচ্ছে...' : 'লাইভ ট্র্যাকিং সক্রিয়'}</span>
                </div>
              </div>
            </div>
            <div className="flex-1 overflow-y-auto no-scrollbar">
               <div className="p-6 rounded-[2.5rem] bg-indigo-50 dark:bg-indigo-900/10 border-2 border-indigo-100 dark:border-indigo-800">
                  <h3 className="text-lg font-black dark:text-white mb-4 leading-tight">{aiInference.reason}</h3>
                  {aiInference.sources && aiInference.sources.length > 0 && (
                    <div className="flex flex-wrap gap-2 pt-4 border-t border-slate-200">
                      {aiInference.sources.map((chunk: any, sidx: number) => (
                        chunk.web && (
                          <a key={sidx} href={chunk.web.uri} target="_blank" rel="noopener noreferrer" className="flex items-center gap-1.5 text-[8px] font-black text-indigo-600 bg-white px-2 py-1 rounded-lg border border-indigo-100 shadow-sm">
                            <Globe className="w-2 h-2" /> Source {sidx+1}
                          </a>
                        )
                      ))}
                    </div>
                  )}
               </div>
            </div>
            <button onClick={() => setSelectedTrain(null)} className="mt-6 w-full bg-slate-900 text-white py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-2xl active:scale-95 transition-all">বন্ধ করুন</button>
          </div>
        </div>
      )}

      {loading ? (
        <div className="space-y-6">{[1,2,3,4].map(i => <div key={i} className="h-40 shimmer rounded-[2.5rem]" />)}</div>
      ) : (
        <div className="space-y-4 animate-slide-up">
           {isInferring && (
             <div className="bg-indigo-50 dark:bg-indigo-900/10 p-8 rounded-[2.5rem] border border-indigo-100 dark:border-indigo-900/30 text-center mb-6">
                <Loader2 className="w-10 h-10 text-indigo-600 animate-spin mx-auto mb-4" />
                <p className="text-sm font-black text-indigo-700 dark:text-indigo-400 uppercase tracking-widest">সর্বশেষ তথ্য খোঁজা হচ্ছে...</p>
             </div>
           )}
           {data.map(item => renderItem(item))}
        </div>
      )}
    </div>
  );
};

export default CategoryView;

