import React, { useState, useEffect } from 'react';
import { 
  Phone, 
  MapPin, 
  Clock as ClockIcon, 
  Loader2, 
  TrainFront,
  X,
  Radar,
  Sparkles,
  History,
  Info,
  Globe,
  RefreshCw,
  ShoppingBasket,
  ArrowUpRight,
  ArrowDownRight,
  Megaphone,
  AlertCircle,
  Briefcase,
  ExternalLink,
  Calendar,
  ChevronRight
} from 'lucide-react';
import { Category, Train, AIInference } from '../types';
import { db } from '../db';
import { Type } from "@google/genai";

interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [isInferring, setIsInferring] = useState(false);
  const [aiInference, setAiInference] = useState<AIInference & { sources?: any[] }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: []
  });

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      const items = await db.getCategory(category);
      setData(items);
      if (category === 'prayer') await fetchLivePrayerTimes();
      setLoading(false);
    };
    fetchData();
  }, [category]);

  const fetchLivePrayerTimes = async () => {
    try {
      // রাজবাড়ী স্থানাঙ্ক ব্যবহার করে সঠিক নামাজের সময়
      const res = await fetch('https://api.aladhan.com/v1/timingsByCity?city=Rajbari&country=Bangladesh&method=1');
      const json = await res.json();
      if (json.code === 200) {
        const t = json.data.timings;
        setData([
          { name: 'ফজর', time: t.Fajr, icon: '🌅' },
          { name: 'যোহর', time: t.Dhuhr, icon: '☀️' },
          { name: 'আসর', time: t.Asr, icon: '🌤️' },
          { name: 'মাগরিব', time: t.Maghrib, icon: '🌇' },
          { name: 'এশা', time: t.Isha, icon: '🌙' },
        ]);
      }
    } catch (e) {}
  };

  const updateWithAI = async () => {
    setIsInferring(true);
    try {
      let prompt = "";
      let schema: any = null;

      if (category === 'market_price') {
        prompt = "Fetch current market prices for essential items like Rice, Oil, Potato, Onion in Rajbari, Bangladesh. Response in JSON.";
        schema = {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              unit: { type: Type.STRING },
              priceRange: { type: Type.STRING },
              trend: { type: Type.STRING }
            },
            required: ['name', 'unit', 'priceRange', 'trend']
          }
        };
      } else if (category === 'notices') {
        prompt = "Find latest emergency notices or administrative news from Rajbari district, Bangladesh. Response in JSON.";
        schema = {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              date: { type: Type.STRING },
              summary: { type: Type.STRING },
              priority: { type: Type.STRING }
            },
            required: ['title', 'date', 'summary', 'priority']
          }
        };
      } else if (category === 'jobs') {
        prompt = "Find latest 5 job circulars for Rajbari District (Govt or reputable private). Response in JSON.";
        schema = {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              org: { type: Type.STRING },
              deadline: { type: Type.STRING },
              eligibility: { type: Type.STRING },
              salary: { type: Type.STRING },
              link: { type: Type.STRING }
            },
            required: ['title', 'org', 'deadline', 'link']
          }
        };
      }

      if (prompt && schema) {
        const response = await db.callAI({
          contents: [{ parts: [{ text: prompt }] }],
          responseMimeType: "application/json",
          responseSchema: schema
        });
        const aiData = JSON.parse(response.text || '[]');
        if (aiData.length > 0) {
          setData(aiData.map((item: any, i: number) => ({ ...item, id: `ai-${category}-${i}`, isAI: true })));
        }
      }
    } catch (e) {
      console.error("AI Error:", e);
    } finally {
      setIsInferring(false);
    }
  };

  const trackTrainAI = async (train: Train) => {
    setIsInferring(true);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'সার্চ করা হচ্ছে...', isAI: true, sources: [] });
    try {
      const response = await db.callAI({
        contents: [{ parts: [{ text: `Find live status or latest delay of train "${train.name} (${train.id})" in Bangladesh. Route: ${train.detailedRoute}.` }] }],
        tools: [{ googleSearch: {} }]
      });
      setAiInference({ 
        delayMinutes: 0, 
