import React, { useState, useEffect } from 'react';
import { 
  Phone, 
  MapPin, 
  Clock as ClockIcon, 
  Loader2, 
  TrainFront,
  X,
  Radar,
  Sparkles,
  History,
  Info,
  Globe,
  RefreshCw,
  ShoppingBasket,
  ArrowUpRight,
  ArrowDownRight,
  Megaphone,
  Briefcase,
  ExternalLink,
  AlertCircle
} from 'lucide-react';
import { Category, Train, AIInference } from '../types';
import { db } from '../db';
import { Type } from "@google/genai";

interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [isInferring, setIsInferring] = useState(false);
  const [aiInference, setAiInference] = useState<AIInference & { sources?: any[] }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: []
  });

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      const items = await db.getCategory(category);
      setData(items);
      if (category === 'prayer') await fetchLivePrayerTimes();
      setLoading(false);
    };
    fetchData();
  }, [category]);

  const fetchLivePrayerTimes = async () => {
    try {
      // রাজবাড়ী স্থানাঙ্ক: Lat 23.7571, Lng 89.6508
      const res = await fetch('https://api.aladhan.com/v1/timingsByCity?city=Rajbari&country=Bangladesh&method=1');
      const json = await res.json();
      if (json.code === 200) {
        const t = json.data.timings;
        setData([
          { name: 'ফজর', time: t.Fajr, icon: '🌅' },
          { name: 'যোহর', time: t.Dhuhr, icon: '☀️' },
          { name: 'আসর', time: t.Asr, icon: '🌤️' },
          { name: 'মাগরিব', time: t.Maghrib, icon: '🌇' },
          { name: 'এশা', time: t.Isha, icon: '🌙' },
        ]);
      }
    } catch (e) { }
  };

  const updateWithAI = async () => {
    setIsInferring(true);
    try {
      let prompt = "";
      let schema: any = null;

      if (category === 'market_price') {
        prompt = "Fetch current market prices for food items like Rice, Oil, Onion in Rajbari, Bangladesh. Response in JSON.";
        schema = {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              unit: { type: Type.STRING },
              priceRange: { type: Type.STRING },
              trend: { type: Type.STRING }
            },
            required: ['name', 'unit', 'priceRange', 'trend']
          }
        };
      } else if (category === 'notices') {
        prompt = "Find latest 3 emergency notices or government announcements from Rajbari district. Response in JSON.";
        schema = {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              date: { type: Type.STRING },
              summary: { type: Type.STRING },
              priority: { type: Type.STRING }
            },
            required: ['title', 'date', 'summary', 'priority']
          }
        };
      } else if (category === 'jobs') {
        prompt = "Find latest job circulars for Rajbari District, Bangladesh. Response in JSON.";
        schema = {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              org: { type: Type.STRING },
              deadline: { type: Type.STRING },
              eligibility: { type: Type.STRING },
              salary: { type: Type.STRING },
              link: { type: Type.STRING }
            },
            required: ['title', 'org', 'deadline', 'link']
          }
        };
      }

      if (prompt && schema) {
        const response = await db.callAI({
          contents: [{ parts: [{ text: prompt }] }],
          responseMimeType: "application/json",
          responseSchema: schema
        });
        const aiData = JSON.parse(response.text || '[]');
        if (aiData.length > 0) {
          setData(aiData.map((item: any, i: number) => ({ ...item, id: `ai-${i}`, isAI: true })));
        }
      }
    } catch (e) {
      console.error("AI Error:", e);
    } finally {
      setIsInferring(false);
    }
  };

  const runAIInference = async (train: Train) => {
    setIsInferring(true);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'সার্চ করা হচ্ছে...', isAI: true, sources: [] });
    try {
      const response = await db.callAI({
        contents: [{ parts: [{ text: `Find live status of train "${train.name} (${train.id})" in Bangladesh.` }] }],
        tools: [{ googleSearch: {} }]
      });
      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0.9, 
        reason: response.text || "তথ্য পাওয়া যায়নি।", 
        isAI: true,
        sources: response.groundingMetadata?.groundingChunks || []
      });
    } catch (e) {
      setAiInference({ delayMinutes: 0, confidence: 0, reason: 'সার্ভার ত্রুটি।', isAI: false });
    } finally {
      setIsInferring(false);
    }
  };

  const renderItem = (item: any) => {
    switch (category) {
      case 'trains':
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-6 group transition-all hover:-translate-y-1">
            <div className="flex items-center gap-4 mb-4">
              <div className="w-12 h-12 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl flex items-center justify-center shadow-inner"><TrainFront className="w-6 h-6" /></div>
              <div className="flex-1">
                <h4 className="font-bold text-slate-800 dark:text-white text-lg">{item.name}</h4>
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.route}</p>
              </div>
              <div className="text-right">
                 <p className="text-[8px] text-slate-400 font-bold uppercase">ছুটি</p>
                 <p className={`text-[10px] font-black uppercase ${item.offDay === 'নাই' ? 'text-emerald-500' : 'text-rose-500'}`}>{item.offDay}</p>
              </div>
            </div>
            <div className="grid grid-cols-2 gap-4 mb-5">
              <div className="bg-slate-50 dark:bg-slate-800/50 p-4 rounded-2xl border border-slate-100 dark:border-slate-800">
                <p className="text-[8px] text-slate-400 font-bold uppercase mb-1">আগমন</p>
                <p className="text-xl font-black dark:text-white tracking-tighter">{item.arrival || '--'}</p>
              </div>
              <div className="bg-slate-50 dark:bg-slate-800/50 p-4 rounded-2xl border border-slate-100 dark:border-slate-800">
                <p className="text-[8px] text-slate-400 font-bold uppercase mb-1">প্রস্থান</p>
                <p className="text-xl font-black text-indigo-600 tracking-tighter">{item.departure}</p>
              </div>
            </div>
            <button onClick={() => { setSelectedTrain(item); runAIInference(item); }} className="w-full bg-indigo-600 text-white py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 shadow-xl hover:bg-indigo-700 active:scale-95 transition-all">
              <Radar className="w-4 h-4 animate-pulse" /> লাইভ রিপোর্ট চেক করুন
            </button>
          </div>
        );
