                <p className="text-xl font-black dark:text-white tracking-tighter">{item.arrival || '--'}</p>
              </div>
              <div className="bg-slate-50 dark:bg-slate-800/50 p-4 rounded-2xl border border-slate-100 dark:border-slate-800">
