               <div className="bg-slate-50 dark:bg-slate-800/50 p-3 rounded-xl border border-slate-100 dark:border-slate-800 shadow-inner">
                  <p className="text-[8px] text-slate-400 font-bold uppercase mb-1">যোগ্যতা ও বেতন</p>
                  <p className="text-[10px] font-black dark:text-white">{item.salary || '--'} | {item.eligibility}</p>
               </div>
               <div className="bg-slate-50 dark:bg-slate-800/50 p-3 rounded-xl border border-slate-100 dark:border-slate-800 shadow-inner">
                  <p className="text-[8px] text-slate-400 font-bold uppercase mb-1">শেষ তারিখ</p>
                  <p className="text-[10px] font-black text-rose-500 uppercase">{item.deadline}</p>
               </div>
            </div>
            <a href={item.link} target="_blank" rel="noopener noreferrer" className="w-full bg-slate-900 dark:bg-indigo-600 text-white py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 shadow-xl hover:scale-[1.02] active:scale-95 transition-all">
              বিস্তারিত ও আবেদন <ExternalLink className="w-4 h-4" />
            </a>
          </div>
        );
      case 'prayer':
        return (
          <div key={item.name} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-4 flex items-center justify-between group transition-all hover:bg-violet-50 dark:hover:bg-violet-950/20 shadow-sm">
            <div className="flex items-center gap-5">
               <div className="text-3xl grayscale group-hover:grayscale-0 transition-all transform group-hover:scale-110">{item.icon}</div>
               <div>
                  <h4 className="font-bold text-slate-800 dark:text-white text-xl">{item.name}</h4>
                  <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">ওয়াক্ত শুরু</p>
               </div>
            </div>
            <div className="bg-slate-50 dark:bg-slate-800 px-6 py-3 rounded-2xl border border-slate-100 dark:border-slate-700 shadow-inner">
               <p className="text-2xl font-black text-indigo-600 tracking-tighter">{item.time}</p>
            </div>
          </div>
        );
      default:
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-4 flex items-center justify-between group shadow-sm transition-all hover:-translate-y-1">
            <div className="flex items-center gap-4">
               <div className="p-3 bg-slate-50 dark:bg-slate-800 rounded-xl text-indigo-600"><Info className="w-5 h-5" /></div>
               <div><h4 className="font-bold dark:text-white text-lg">{item.name || item.title}</h4><p className="text-xs text-slate-400 font-bold">{item.address || item.details || item.number || item.mobile}</p></div>
            </div>
            {(item.mobile || item.number) && <a href={`tel:${item.mobile || item.number}`} className="p-4 bg-indigo-50 dark:bg-slate-800 rounded-2xl text-indigo-600 active:scale-90 transition-all shadow-md"><Phone className="w-6 h-6" /></a>}
          </div>
        );
    }
  };

  return (
    <div className="px-6 py-6 pb-32">
      <div className="flex items-center justify-between mb-8 px-2">
         <div className="flex flex-col">
           <h3 className="text-2xl font-black text-slate-800 dark:text-white tracking-tighter uppercase">
             {category === 'market_price' ? 'লাইভ বাজারদর' : category === 'prayer' ? 'নামাজের সময়' : category === 'notices' ? 'সর্বশেষ নোটিশ' : category === 'jobs' ? 'চাকরি বিজ্ঞপ্তি' : 'তালিকা'}
           </h3>
           <p className="text-[10px] font-black text-indigo-500 uppercase tracking-[0.4em]">District Portal</p>
         </div>
         {(['market_price', 'notices', 'jobs'].includes(category)) && (
           <button onClick={updateWithAI} disabled={isInferring} className={`p-4 bg-indigo-600 text-white rounded-2xl shadow-xl active:scale-90 transition-all ${isInferring ? 'animate-spin opacity-50' : ''}`}>
             <RefreshCw className="w-5 h-5" />
           </button>
         )}
         {category === 'prayer' && (
           <button onClick={fetchLivePrayerTimes} className="p-4 bg-violet-600 text-white rounded-2xl shadow-xl active:scale-90 transition-all">
             <RefreshCw className="w-5 h-5" />
           </button>
         )}
      </div>

      {selectedTrain && (
        <div className="fixed inset-0 z-[200] bg-slate-950/90 backdrop-blur-xl flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 w-full max-w-lg rounded-[3rem] p-6 shadow-3xl flex flex-col max-h-[90vh] animate-slide-up relative border border-white/10">
            <button onClick={() => setSelectedTrain(null)} className="absolute right-6 top-6 p-3 bg-slate-100 dark:bg-slate-800 rounded-2xl text-slate-500 z-10"><X className="w-6 h-6" /></button>
            <div className="flex items-center gap-4 mb-8">
              <div className="bg-indigo-600 p-4 rounded-2xl text-white shadow-xl">
                {isInferring ? <Loader2 className="w-6 h-6 animate-spin" /> : <TrainFront className="w-6 h-6" />}
              </div>
              <div>
                <h4 className="text-xl font-black dark:text-white uppercase tracking-tighter">{selectedTrain.name}</h4>
                <div className="flex items-center gap-2">
                  <div className={`w-2 h-2 rounded-full animate-ping ${isInferring ? 'bg-amber-500' : 'bg-emerald-500'}`}></div>
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{isInferring ? 'সার্চ করা হচ্ছে...' : 'লাইভ ট্র্যাকিং সক্রিয়'}</span>
                </div>
              </div>
            </div>
            <div className="flex-1 overflow-y-auto no-scrollbar pr-1">
               <div className="p-6 rounded-[2.5rem] bg-indigo-50 dark:bg-indigo-900/10 border-2 border-indigo-100 dark:border-indigo-800 shadow-inner">
                  <h3 className="text-lg font-black dark:text-white mb-4 leading-tight">{aiInference.reason}</h3>
                  {aiInference.sources && aiInference.sources.length > 0 && (
                    <div className="flex flex-wrap gap-2 pt-4 border-t border-slate-200 dark:border-slate-700">
                      {aiInference.sources.map((chunk: any, sidx: number) => (
                        chunk.web && (
                          <a key={sidx} href={chunk.web.uri} target="_blank" rel="noopener noreferrer" className="flex items-center gap-1.5 text-[8px] font-black text-indigo-600 bg-white px-2 py-1 rounded-lg border border-indigo-100 shadow-sm">
                            <Globe className="w-2 h-2" /> Source {sidx+1}
                          </a>
                        )
                      ))}
                    </div>
                  )}
               </div>
            </div>
            <button onClick={() => setSelectedTrain(null)} className="mt-6 w-full bg-slate-900 text-white py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-2xl active:scale-95 transition-all">বন্ধ করুন</button>
          </div>
        </div>
      )}

      {loading ? (
        <div className="space-y-6">{[1,2,3,4].map(i => <div key={i} className="h-40 shimmer rounded-[2.5rem]" />)}</div>
      ) : (
        <div className="space-y-4 animate-slide-up">
           {isInferring && (
             <div className="bg-indigo-50 dark:bg-indigo-900/10 p-8 rounded-[2.5rem] border border-indigo-100 dark:border-indigo-900/30 text-center mb-6">
                <Loader2 className="w-10 h-10 text-indigo-600 animate-spin mx-auto mb-4" />
                <p className="text-sm font-black text-indigo-700 dark:text-indigo-400 uppercase tracking-widest">সর্বশেষ তথ্য খোঁজা হচ্ছে...</p>
             </div>
           )}
           {data.map(item => renderItem(item))}
        </div>
      )}
    </div>
  );
};

export default CategoryView;

import React, { useState, useEffect } from 'react';
import { 
  Phone, 
  MapPin, 
  Clock as ClockIcon, 
  Loader2, 
  TrainFront,
  X,
  Radar,
  Sparkles,
  History,
  Info,
  Globe,
  RefreshCw,
  ShoppingBasket,
  ArrowUpRight,
  ArrowDownRight,
  Megaphone,
  Briefcase,
  ExternalLink,
  AlertCircle
} from 'lucide-react';
import { Category, Train, AIInference } from '../types';
import { db } from '../db';
import { Type } from "@google/genai";

interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [aiInference, setAiInference] = useState<AIInference & { likelyCurrentStation?: string, sources?: any[], rawText?: string }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: [],
    rawText: ''
  });
  const [isInferring, setIsInferring] = useState(false);
  const [liveInfo, setLiveInfo] = useState<{currentStation: string, progress: number, status: string, nextStation?: string, stationIndex: number, isOffDay?: boolean, lastUpdated?: string} | null>(null);

  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      setCurrentTime(now);
      if (selectedTrain) {
        setLiveInfo(calculateLiveLocation(selectedTrain, aiInference));
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [selectedTrain, aiInference]);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      const items = await db.getCategory(category);
      setData(items);
      if (category === 'prayer') await fetchLivePrayerTimes();
      setLoading(false);
    };
    fetchData();
  }, [category]);

  const updateWithAI = async () => {
    setIsInferring(true);
    try {
      let prompt = "";
      let schema: any = null;

      if (category === 'market_price') {
        prompt = "Fetch current market prices for essential food items like Rice, Oil, Onion in Rajbari, Bangladesh. Response in JSON.";
        schema = {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              unit: { type: Type.STRING },
              priceRange: { type: Type.STRING },
              trend: { type: Type.STRING }
            },
            required: ['name', 'unit', 'priceRange', 'trend']
          }
        };
      } else if (category === 'notices') {
        prompt = "Find latest 3 emergency notices or government announcements from Rajbari district. Response in JSON.";
        schema = {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              date: { type: Type.STRING },
              summary: { type: Type.STRING },
              priority: { type: Type.STRING }
            },
            required: ['title', 'date', 'summary', 'priority']
          }
        };
      } else if (category === 'jobs') {
        prompt = "Find latest job circulars for Rajbari District, Bangladesh. Response in JSON.";
        schema = {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              org: { type: Type.STRING },
              deadline: { type: Type.STRING },
              eligibility: { type: Type.STRING },
              salary: { type: Type.STRING },
              link: { type: Type.STRING }
            },
            required: ['title', 'org', 'deadline', 'link']
          }
        };
      }

      if (prompt && schema) {
        const response = await db.callAI({
          contents: [{ parts: [{ text: prompt }] }],
          responseMimeType: "application/json",
          responseSchema: schema
        });
        const aiData = JSON.parse(response.text || '[]');
        if (aiData.length > 0) {
          setData(aiData.map((item: any, i: number) => ({ ...item, id: `ai-${i}`, isAI: true })));
        }
      }
    } catch (e) {
      console.error("AI Error:", e);
    } finally {
      setIsInferring(false);
    }
  };

  const runAIInference = async (train: Train) => {
    setIsInferring(true);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'ফেসবুক ও ট্র্যাকিং ওয়েবসাইট থেকে লাইভ ডাটা খোঁজা হচ্ছে...', isAI: true, sources: [] });

    try {
      const prompt = `SEARCH COMMAND: 
      ১. "${train.name} (${train.id})" ট্রেনের বর্তমান অবস্থান কি?
      ২. "বাংলাদেশ রেলওয়ে ফ্যান গ্রুপ" এবং "রাজবাড়ী ট্রেন ক্লাব" ফেসবুক পেজ বা গ্রুপে গত ১ ঘণ্টার কোনো পোস্ট আছে কিনা দেখুন।
      ৩. ট্রেনটির রুট: ${train.detailedRoute}।
      ৪. বর্তমান সময়: ${currentTime.toLocaleTimeString('bn-BD')}।

      তথ্যসূত্রসহ বিস্তারিত উত্তর দিন। যদি সুনির্দিষ্ট লোকেশন পান, তবে নিচের JSON ফরম্যাটে দিন:
      {
        "delayMinutes": 0,
        "confidence": 0.9,
        "reason": "লোকেশন রিপোর্ট এখানে",
        "likelyCurrentStation": "স্টেশনের নাম"
      }`;

      const response = await db.callAI({
        contents: [{ parts: [{ text: prompt }] }]
      });

      const text = response.text || '';
      const sources = response.groundingMetadata?.groundingChunks || [];

      const start = text.indexOf('{');
      const end = text.lastIndexOf('}');
      if (start !== -1 && end !== -1) {
        try {
          const jsonPart = JSON.parse(text.substring(start, end + 1));
          setAiInference({ ...jsonPart, isAI: true, sources, rawText: text });
        } catch(e) {
          setAiInference({ delayMinutes: 0, confidence: 0.6, reason: text, isAI: true, sources, rawText: text });
        }
      } else {
        setAiInference({ delayMinutes: 0, confidence: 0.6, reason: text, isAI: true, sources, rawText: text });
      }
    } catch (e) {
      setAiInference({ delayMinutes: 0, confidence: 0, reason: 'সার্ভারে সমস্যা হয়েছে। পুনরায় চেষ্টা করুন।', isAI: false, sources: [] });
    } finally { setIsInferring(false); }
  };

  const calculateLiveLocation = (train: Train, inference: AIInference & { likelyCurrentStation?: string }) => {
    const stations = train.detailedRoute?.split(',').map(s => s.trim()) || [];
    if (stations.length === 0) return null;

    if (inference.isAI && inference.likelyCurrentStation && inference.confidence > 0.4) {
      const foundIdx = stations.findIndex(s => s.toLowerCase().includes(inference.likelyCurrentStation!.toLowerCase().trim()));
      if (foundIdx !== -1) {
        return { 
          currentStation: stations[foundIdx], 
          progress: Math.floor((foundIdx / (stations.length - 1)) * 100), 
          status: `লাইভ রিপোর্ট: ${stations[foundIdx]}`, 
          stationIndex: foundIdx 
        };
      }
    }

    const bnDigits: {[key: string]: string} = { '০': '0', '১': '1', '২': '2', '৩': '3', '৪': '4', '৫': '5', '৬': '6', '৭': '7', '৮': '8', '৯': '9' };
    const normTime = train.departure === 'Start' ? '06:00 AM' : train.departure.replace(/[০-৯]/g, m => bnDigits[m]);
    const [t, ampm] = normTime.split(' ');
    let [h, m] = t.split(':').map(Number);
    if (ampm === 'PM' && h < 12) h += 12;
    if (ampm === 'AM' && h === 12) h = 0;
    const dep = new Date(currentTime);
    dep.setHours(h, m, 0, 0);
    const diff = Math.floor((currentTime.getTime() - dep.getTime()) / 60000);

    if (diff < 0) return { currentStation: stations[0], progress: 0, status: 'ছাড়ার অপেক্ষায়', stationIndex: 0 };
    const idx = Math.min(Math.max(0, Math.floor(diff / 20)), stations.length - 1);
    return { currentStation: stations[idx], progress: Math.floor((idx / (stations.length - 1)) * 100), status: 'সম্ভাব্য অবস্থান (শিডিউল)', stationIndex: idx };
  };

  const fetchLivePrayerTimes = async () => {
    try {
      const res = await fetch('https://api.aladhan.com/v1/timingsByCity?city=Rajbari&country=Bangladesh&method=1');
      const json = await res.json();
      if (json.code === 200) {
        const t = json.data.timings;
        setData([
          { name: 'ফজর', time: t.Fajr, icon: '🌅' },
          { name: 'যোহর', time: t.Dhuhr, icon: '☀️' },
          { name: 'আসর', time: t.Asr, icon: '🌤️' },
          { name: 'মাগরিব', time: t.Maghrib, icon: '🌇' },
          { name: 'এশা', time: t.Isha, icon: '🌙' },
        ]);
      }
    } catch (e) { }
  };

  const renderItem = (item: any) => {
    switch (category) {
      case 'trains':
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-6 animate-slide-up group">
            <div className="flex items-center gap-4 mb-4">
              <div className="w-12 h-12 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl flex items-center justify-center shadow-inner"><TrainFront className="w-6 h-6" /></div>
              <div className="flex-1">
                <h4 className="font-bold text-slate-800 dark:text-white text-lg">{item.name}</h4>
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.route}</p>
              </div>
              <div className="text-right">
                 <p className="text-[8px] text-slate-400 font-bold uppercase">ছুটি</p>
                 <p className={`text-[10px] font-black uppercase ${item.offDay === 'নাই' ? 'text-emerald-500' : 'text-rose-500'}`}>{item.offDay}</p>
              </div>
            </div>
            <div className="grid grid-cols-2 gap-4 mb-5">
              <div className="bg-slate-50 dark:bg-slate-800/50 p-4 rounded-2xl border border-slate-100 dark:border-slate-800">
                <p className="text-[8px] text-slate-400 font-bold uppercase mb-1">আগমন</p>
                <p className="text-xl font-black dark:text-white tracking-tighter">{item.arrival || '--'}</p>
              </div>
              <div className="bg-slate-50 dark:bg-slate-800/50 p-4 rounded-2xl border border-slate-100 dark:border-slate-800">
                <p className="text-[8px] text-slate-400 font-bold uppercase mb-1">প্রস্থান</p>
                <p className="text-xl font-black text-indigo-600 tracking-tighter">{item.departure}</p>
              </div>
            </div>
            <button onClick={() => { setSelectedTrain(item); runAIInference(item); }} className="w-full bg-indigo-600 text-white py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 shadow-xl active:scale-95 transition-all">
              <Radar className="w-4 h-4 animate-pulse" /> লাইভ রিপোর্ট চেক করুন
            </button>
          </div>
        );
      case 'market_price':
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 flex items-center justify-between mb-4 group transition-all hover:bg-lime-50 dark:hover:bg-lime-950/20">
             <div className="flex items-center gap-4">
                <div className="p-4 bg-lime-50 dark:bg-lime-900/20 text-lime-600 rounded-2xl"><ShoppingBasket className="w-6 h-6" /></div>
                <div>
                   <h4 className="font-bold dark:text-white text-lg">{item.name}</h4>
                   <p className="text-xs text-slate-400 font-bold uppercase">{item.unit}</p>
                </div>
             </div>
             <div className="text-right">
                <div className="flex items-center justify-end gap-1.5 mb-1">
                   {item.isAI && <Sparkles className="w-3 h-3 text-amber-500 animate-pulse" />}
                   <p className="text-xl font-black text-indigo-600 tracking-tighter">{item.priceRange}</p>
                </div>
                <div className={`flex items-center justify-end gap-1 text-[8px] font-black uppercase ${item.trend === 'up' ? 'text-rose-500' : item.trend === 'down' ? 'text-emerald-500' : 'text-slate-400'}`}>
                   {item.trend === 'up' ? <ArrowUpRight className="w-3 h-3" /> : item.trend === 'down' ? <ArrowDownRight className="w-3 h-3" /> : null}
                   {item.trend === 'up' ? 'বাড়তি' : item.trend === 'down' ? 'কমছে' : 'স্থিতিশীল'}
                </div>
             </div>
          </div>
        );
      case 'notices':
        return (
          <div key={item.id} className={`bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] border ${item.priority === 'high' ? 'border-rose-200 shadow-rose-50' : 'border-slate-50'} mb-6 relative overflow-hidden transition-all hover:shadow-lg`}>
            {item.priority === 'high' && <div className="absolute top-0 right-0 bg-rose-500 text-white text-[8px] font-black uppercase px-4 py-1 rounded-bl-xl tracking-widest">Emergency</div>}
            <div className="flex gap-4 mb-4">
               <div className={`p-4 rounded-2xl ${item.priority === 'high' ? 'bg-rose-50 text-rose-600' : 'bg-orange-50 text-orange-600'}`}>
                 <Megaphone className="w-6 h-6" />
               </div>
               <div>
                  <h4 className="font-bold text-slate-800 dark:text-white text-lg leading-tight">{item.title}</h4>
                  <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">{item.date}</p>
               </div>
            </div>
            <p className="text-sm text-slate-600 dark:text-slate-400 italic bg-slate-50 dark:bg-slate-800/50 p-4 rounded-2xl border border-slate-100 dark:border-slate-800">
              {item.summary}
            </p>
          </div>
        );
      case 'jobs':
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-6 group transition-all hover:border-purple-200">
            <div className="flex items-center gap-4 mb-5">
               <div className="p-4 bg-purple-50 text-purple-600 rounded-2xl"><Briefcase className="w-6 h-6" /></div>
               <div className="flex-1">
                  <h4 className="font-bold text-slate-800 dark:text-white text-lg leading-tight group-hover:text-indigo-600 transition-colors">{item.title}</h4>
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">{item.org}</p>
               </div>
            </div>
            <div className="grid grid-cols-2 gap-3 mb-6">
               <div className="bg-slate-50 dark:bg-slate-800/50 p-3 rounded-xl border border-slate-100 dark:border-slate-800 shadow-inner">
                  <p className="text-[8px] text-slate-400 font-bold uppercase mb-1">যোগ্যতা ও বেতন</p>
                  <p className="text-[10px] font-black dark:text-white">{item.salary || '--'} | {item.eligibility}</p>
               </div>
               <div className="bg-slate-50 dark:bg-slate-800/50 p-3 rounded-xl border border-slate-100 dark:border-slate-800 shadow-inner">
                  <p className="text-[8px] text-slate-400 font-bold uppercase mb-1">শেষ তারিখ</p>
                  <p className="text-[10px] font-black text-rose-500 uppercase">{item.deadline}</p>
               </div>
            </div>
            <a href={item.link} target="_blank" rel="noopener noreferrer" className="w-full bg-slate-900 dark:bg-indigo-600 text-white py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 shadow-xl hover:scale-[1.02] active:scale-95 transition-all">
              বিস্তারিত ও আবেদন <ExternalLink className="w-4 h-4" />
            </a>
          </div>
        );
      case 'prayer':
        return (
          <div key={item.name} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-4 flex items-center justify-between group transition-all hover:bg-violet-50 dark:hover:bg-violet-950/20 shadow-sm">
            <div className="flex items-center gap-5">
               <div className="text-3xl grayscale group-hover:grayscale-0 transition-all transform group-hover:scale-110">{item.icon}</div>
               <div>
                  <h4 className="font-bold text-slate-800 dark:text-white text-xl">{item.name}</h4>
                  <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">ওয়াক্ত শুরু</p>
               </div>
            </div>
            <div className="bg-slate-50 dark:bg-slate-800 px-6 py-3 rounded-2xl border border-slate-100 dark:border-slate-700 shadow-inner">
               <p className="text-2xl font-black text-indigo-600 tracking-tighter">{item.time}</p>
            </div>
          </div>
        );
      default:
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-4 flex items-center justify-between group shadow-sm transition-all hover:-translate-y-1">
            <div className="flex items-center gap-4">
               <div className="p-3 bg-slate-50 dark:bg-slate-800 rounded-xl text-indigo-600"><Info className="w-5 h-5" /></div>
               <div><h4 className="font-bold dark:text-white text-lg">{item.name || item.title}</h4><p className="text-xs text-slate-400 font-bold">{item.address || item.details || item.number || item.mobile}</p></div>
            </div>
            {(item.mobile || item.number) && <a href={`tel:${item.mobile || item.number}`} className="p-4 bg-indigo-50 dark:bg-slate-800 rounded-2xl text-indigo-600 active:scale-90 transition-all shadow-md"><Phone className="w-6 h-6" /></a>}
          </div>
        );
    }
  };

  return (
    <div className="px-6 py-6 pb-32">
      <div className="flex items-center justify-between mb-8 px-2">
         <div className="flex flex-col">
           <h3 className="text-2xl font-black text-slate-800 dark:text-white tracking-tighter uppercase">
             {category === 'market_price' ? 'লাইভ বাজারদর' : category === 'prayer' ? 'নামাজের সময়' : category === 'notices' ? 'সর্বশেষ নোটিশ' : category === 'jobs' ? 'চাকরি বিজ্ঞপ্তি' : 'তালিকা'}
           </h3>
           <p className="text-[10px] font-black text-indigo-500 uppercase tracking-[0.4em]">District Portal</p>
         </div>
         {(['market_price', 'notices', 'jobs'].includes(category)) && (
           <button onClick={updateWithAI} disabled={isInferring} className={`p-4 bg-indigo-600 text-white rounded-2xl shadow-xl active:scale-90 transition-all ${isInferring ? 'animate-spin opacity-50' : ''}`}>
             <RefreshCw className="w-5 h-5" />
           </button>
         )}
         {category === 'prayer' && (
           <button onClick={fetchLivePrayerTimes} className="p-4 bg-violet-600 text-white rounded-2xl shadow-xl active:scale-90 transition-all">
             <RefreshCw className="w-5 h-5" />
           </button>
         )}
      </div>

      {selectedTrain && (
        <div className="fixed inset-0 z-[200] bg-slate-950/90 backdrop-blur-xl flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 w-full max-w-lg rounded-[3rem] p-6 shadow-3xl flex flex-col max-h-[90vh] animate-slide-up relative border border-white/10">
            <button onClick={() => setSelectedTrain(null)} className="absolute right-6 top-6 p-3 bg-slate-100 dark:bg-slate-800 rounded-2xl text-slate-500 z-10"><X className="w-6 h-6" /></button>
            <div className="flex items-center gap-4 mb-8">
              <div className="bg-indigo-600 p-4 rounded-2xl text-white shadow-xl">
                {isInferring ? <Loader2 className="w-6 h-6 animate-spin" /> : <TrainFront className="w-6 h-6" />}
              </div>
              <div>
                <h4 className="text-xl font-black dark:text-white uppercase tracking-tighter">{selectedTrain.name}</h4>
                <div className="flex items-center gap-2">
                  <div className={`w-2 h-2 rounded-full animate-ping ${isInferring ? 'bg-amber-500' : 'bg-emerald-500'}`}></div>
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{isInferring ? 'সার্চ করা হচ্ছে...' : 'লাইভ ট্র্যাকিং সক্রিয়'}</span>
                </div>
              </div>
            </div>
            <div className="flex-1 overflow-y-auto no-scrollbar pr-1">
               <div className="p-6 rounded-[2.5rem] bg-indigo-50 dark:bg-indigo-900/10 border-2 border-indigo-100 dark:border-indigo-800 shadow-inner">
                  <h3 className="text-lg font-black dark:text-white mb-4 leading-tight">{aiInference.reason}</h3>
                  {aiInference.sources && aiInference.sources.length > 0 && (
                    <div className="flex flex-wrap gap-2 pt-4 border-t border-slate-200 dark:border-slate-700">
                      {aiInference.sources.map((chunk: any, sidx: number) => (
                        chunk.web && (
                          <a key={sidx} href={chunk.web.uri} target="_blank" rel="noopener noreferrer" className="flex items-center gap-1.5 text-[8px] font-black text-indigo-600 bg-white px-2 py-1 rounded-lg border border-indigo-100 shadow-sm">
                            <Globe className="w-2 h-2" /> Source {sidx+1}
                          </a>
                        )
                      ))}
                    </div>
                  )}
               </div>
            </div>
            <button onClick={() => setSelectedTrain(null)} className="mt-6 w-full bg-slate-900 text-white py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-2xl active:scale-95 transition-all">বন্ধ করুন</button>
          </div>
        </div>
      )}

      {loading ? (
        <div className="space-y-6">{[1,2,3,4].map(i => <div key={i} className="h-40 shimmer rounded-[2.5rem]" />)}</div>
      ) : (
        <div className="space-y-4 animate-slide-up">
           {isInferring && (
             <div className="bg-indigo-50 dark:bg-indigo-900/10 p-8 rounded-[2.5rem] border border-indigo-100 dark:border-indigo-900/30 text-center mb-6">
                <Loader2 className="w-10 h-10 text-indigo-600 animate-spin mx-auto mb-4" />
                <p className="text-sm font-black text-indigo-700 dark:text-indigo-400 uppercase tracking-widest">সর্বশেষ তথ্য খোঁজা হচ্ছে...</p>
             </div>
           )}
           {data.map(item => renderItem(item))}
        </div>
      )}
    </div>
  );
};

export default CategoryView;

import React, { useState, useEffect } from 'react';
import { 
  Phone, 
  MapPin, 
  Clock as ClockIcon, 
  Loader2, 
  TrainFront,
  X,
  Radar,
  Sparkles,
  History,
  Info,
  Globe,
  RefreshCw,
  ShoppingBasket,
  ArrowUpRight,
  ArrowDownRight,
  Megaphone,
  Briefcase,
  ExternalLink,
  AlertCircle
} from 'lucide-react';
import { Category, Train, AIInference } from '../types';
import { db } from '../db';
import { Type } from "@google/genai";

interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [isInferring, setIsInferring] = useState(false);
  const [aiInference, setAiInference] = useState<AIInference & { likelyCurrentStation?: string, sources?: any[], rawText?: string }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: [],
    rawText: ''
  });
  const [liveInfo, setLiveInfo] = useState<{currentStation: string, progress: number, status: string, nextStation?: string, stationIndex: number, isOffDay?: boolean, lastUpdated?: string} | null>(null);

  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      setCurrentTime(now);
      if (selectedTrain) {
        setLiveInfo(calculateLiveLocation(selectedTrain, aiInference));
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [selectedTrain, aiInference]);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      const items = await db.getCategory(category);
      setData(items);
      if (category === 'prayer') await fetchLivePrayerTimes();
      setLoading(false);
    };
    fetchData();
  }, [category]);

  // ==========================================
  // TRAIN LOGIC (DO NOT TOUCH - LOCK)
  // ==========================================
  const runAIInference = async (train: Train) => {
    setIsInferring(true);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'ফেসবুক ও ট্র্যাকিং ওয়েবসাইট থেকে লাইভ ডাটা খোঁজা হচ্ছে...', isAI: true, sources: [] });

    try {
      const prompt = `SEARCH COMMAND: 
      ১. "${train.name} (${train.id})" ট্রেনের বর্তমান অবস্থান কি?
      ২. "বাংলাদেশ রেলওয়ে ফ্যান গ্রুপ" এবং "রাজবাড়ী ট্রেন ক্লাব" ফেসবুক পেজ বা গ্রুপে গত ১ ঘণ্টার কোনো পোস্ট আছে কিনা দেখুন।
      ৩. ট্রেনটির রুট: ${train.detailedRoute}।
      ৪. বর্তমান সময়: ${currentTime.toLocaleTimeString('bn-BD')}।

      তথ্যসূত্রসহ বিস্তারিত উত্তর দিন। যদি সুনির্দিষ্ট লোকেশন পান, তবে নিচের JSON ফরম্যাটে দিন:
      {
        "delayMinutes": 0,
        "confidence": 0.9,
        "reason": "লোকেশন রিপোর্ট এখানে",
        "likelyCurrentStation": "স্টেশনের নাম"
      }`;

      const response = await db.callAI({
        contents: [{ parts: [{ text: prompt }] }]
      });

      const text = response.text || '';
      const sources = response.groundingMetadata?.groundingChunks || [];

      const start = text.indexOf('{');
      const end = text.lastIndexOf('}');
      if (start !== -1 && end !== -1) {
        try {
          const jsonPart = JSON.parse(text.substring(start, end + 1));
          setAiInference({ ...jsonPart, isAI: true, sources, rawText: text });
        } catch(e) {
          setAiInference({ delayMinutes: 0, confidence: 0.6, reason: text, isAI: true, sources, rawText: text });
        }
      } else {
        setAiInference({ delayMinutes: 0, confidence: 0.6, reason: text, isAI: true, sources, rawText: text });
      }
    } catch (e) {
      setAiInference({ delayMinutes: 0, confidence: 0, reason: 'সার্ভারে সমস্যা হয়েছে। পুনরায় চেষ্টা করুন।', isAI: false, sources: [] });
    } finally { setIsInferring(false); }
  };

  const calculateLiveLocation = (train: Train, inference: AIInference & { likelyCurrentStation?: string }) => {
    const stations = train.detailedRoute?.split(',').map(s => s.trim()) || [];
    if (stations.length === 0) return null;

    if (inference.isAI && inference.likelyCurrentStation && inference.confidence > 0.4) {
      const foundIdx = stations.findIndex(s => s.toLowerCase().includes(inference.likelyCurrentStation!.toLowerCase().trim()));
      if (foundIdx !== -1) {
        return { 
          currentStation: stations[foundIdx], 
          progress: Math.floor((foundIdx / (stations.length - 1)) * 100), 
          status: `লাইভ রিপোর্ট: ${stations[foundIdx]}`, 
          stationIndex: foundIdx 
        };
      }
    }

    const bnDigits: {[key: string]: string} = { '০': '0', '১': '1', '২': '2', '৩': '3', '৪': '4', '৫': '5', '৬': '6', '৭': '7', '৮': '8', '৯': '9' };
    const normTime = train.departure === 'Start' ? '06:00 AM' : train.departure.replace(/[০-৯]/g, m => bnDigits[m]);
    const [t, ampm] = normTime.split(' ');
    let [h, m] = t.split(':').map(Number);
    if (ampm === 'PM' && h < 12) h += 12;
    if (ampm === 'AM' && h === 12) h = 0;
    const dep = new Date(currentTime);
    dep.setHours(h, m, 0, 0);
    const diff = Math.floor((currentTime.getTime() - dep.getTime()) / 60000);

    if (diff < 0) return { currentStation: stations[0], progress: 0, status: 'ছাড়ার অপেক্ষায়', stationIndex: 0 };
    const idx = Math.min(Math.max(0, Math.floor(diff / 20)), stations.length - 1);
    return { currentStation: stations[idx], progress: Math.floor((idx / (stations.length - 1)) * 100), status: 'সম্ভাব্য অবস্থান (শিডিউল)', stationIndex: idx };
  };
  // ==========================================

  const fetchLivePrayerTimes = async () => {
    try {
      const res = await fetch('https://api.aladhan.com/v1/timingsByCity?city=Rajbari&country=Bangladesh&method=1');
      const json = await res.json();
      if (json.code === 200) {
        const t = json.data.timings;
        setData([
          { name: 'ফজর', time: t.Fajr, icon: '🌅' },
          { name: 'যোহর', time: t.Dhuhr, icon: '☀️' },
          { name: 'আসর', time: t.Asr, icon: '🌤️' },
          { name: 'মাগরিব', time: t.Maghrib, icon: '🌇' },
          { name: 'এশা', time: t.Isha, icon: '🌙' },
        ]);
      }
    } catch (e) {
      console.warn("Prayer API failed, keeping current data.");
    }
  };

  const updateWithAI = async () => {
    setIsInferring(true);
    try {
      let prompt = "";
      let schema: any = null;

      if (category === 'market_price') {
        prompt = "Fetch current market prices for essential food items like Rice, Oil, Onion in Rajbari District, Bangladesh. Response in JSON.";
        schema = {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              unit: { type: Type.STRING },
              priceRange: { type: Type.STRING },
              trend: { type: Type.STRING }
            },
            required: ['name', 'unit', 'priceRange', 'trend']
          }
        };
      } else if (category === 'notices') {
        prompt = "Find latest emergency notices or government announcements from Rajbari district, Bangladesh. Response in JSON.";
        schema = {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              date: { type: Type.STRING },
              summary: { type: Type.STRING },
              priority: { type: Type.STRING }
            },
            required: ['title', 'date', 'summary', 'priority']
          }
        };
      } else if (category === 'jobs') {
        prompt = "Find latest job circulars for Rajbari District, Bangladesh (Govt or Private). Response in JSON.";
        schema = {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              org: { type: Type.STRING },
              deadline: { type: Type.STRING },
              eligibility: { type: Type.STRING },
              salary: { type: Type.STRING },
              link: { type: Type.STRING }
            },
            required: ['title', 'org', 'deadline', 'link']
          }
        };
      }

      if (prompt && schema) {
        const response = await db.callAI({
          contents: [{ parts: [{ text: prompt }] }],
          responseMimeType: "application/json",
          responseSchema: schema
        });
        const aiData = JSON.parse(response.text || '[]');
        if (aiData.length > 0) {
          setData(aiData.map((item: any, i: number) => ({ ...item, id: `ai-${i}`, isAI: true })));
        }
      }
    } catch (e) {
      console.error("AI Update Failed:", e);
    } finally {
      setIsInferring(false);
    }
  };

  const renderItem = (item: any) => {
    switch (category) {
      case 'trains':
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-6 animate-slide-up group">
            <div className="flex items-center gap-4 mb-4">
              <div className="w-12 h-12 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl flex items-center justify-center shadow-inner"><TrainFront className="w-6 h-6" /></div>
              <div className="flex-1">
                <h4 className="font-bold text-slate-800 dark:text-white text-lg">{item.name}</h4>
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.route}</p>
              </div>
              <div className="text-right">
                 <p className="text-[8px] text-slate-400 font-bold uppercase">ছুটি</p>
                 <p className={`text-[10px] font-black uppercase ${item.offDay === 'নাই' ? 'text-emerald-500' : 'text-rose-500'}`}>{item.offDay}</p>
              </div>
            </div>
            <div className="grid grid-cols-2 gap-4 mb-5">
              <div className="bg-slate-50 dark:bg-slate-800/50 p-4 rounded-2xl border border-slate-100 dark:border-slate-800">
                <p className="text-[8px] text-slate-400 font-bold uppercase mb-1">আগমন</p>
                <p className="text-xl font-black dark:text-white tracking-tighter">{item.arrival || '--'}</p>
              </div>
              <div className="bg-slate-50 dark:bg-slate-800/50 p-4 rounded-2xl border border-slate-100 dark:border-slate-800">
                <p className="text-[8px] text-slate-400 font-bold uppercase mb-1">প্রস্থান</p>
                <p className="text-xl font-black text-indigo-600 tracking-tighter">{item.departure}</p>
              </div>
            </div>
            <button onClick={() => { setSelectedTrain(item); runAIInference(item); }} className="w-full bg-indigo-600 text-white py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 shadow-xl active:scale-95 transition-all">
              <Radar className="w-4 h-4 animate-pulse" /> লাইভ রিপোর্ট চেক করুন
            </button>
          </div>
        );
      case 'market_price':
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 flex items-center justify-between mb-4 group transition-all hover:bg-lime-50 dark:hover:bg-lime-950/20 shadow-sm">
             <div className="flex items-center gap-4">
                <div className="p-4 bg-lime-50 dark:bg-lime-900/20 text-lime-600 rounded-2xl"><ShoppingBasket className="w-6 h-6" /></div>
                <div>
                   <h4 className="font-bold dark:text-white text-lg">{item.name}</h4>
                   <p className="text-xs text-slate-400 font-bold uppercase">{item.unit}</p>
                </div>
             </div>
             <div className="text-right">
                <div className="flex items-center justify-end gap-1.5 mb-1">
                   {item.isAI && <Sparkles className="w-3 h-3 text-amber-500 animate-pulse" />}
                   <p className="text-xl font-black text-indigo-600 tracking-tighter">{item.priceRange}</p>
                </div>
                <div className={`flex items-center justify-end gap-1 text-[8px] font-black uppercase ${item.trend === 'up' ? 'text-rose-500' : item.trend === 'down' ? 'text-emerald-500' : 'text-slate-400'}`}>
                   {item.trend === 'up' ? <ArrowUpRight className="w-3 h-3" /> : item.trend === 'down' ? <ArrowDownRight className="w-3 h-3" /> : null}
                   {item.trend === 'up' ? 'বাড়তি' : item.trend === 'down' ? 'কমছে' : 'স্থিতিশীল'}
                </div>
             </div>
          </div>
        );
      case 'notices':
        return (
          <div key={item.id} className={`bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] border ${item.priority === 'high' ? 'border-rose-200 shadow-rose-50' : 'border-slate-50'} mb-6 relative overflow-hidden transition-all hover:shadow-lg shadow-sm`}>
            {item.priority === 'high' && <div className="absolute top-0 right-0 bg-rose-500 text-white text-[8px] font-black uppercase px-4 py-1 rounded-bl-xl tracking-widest">Emergency</div>}
            <div className="flex gap-4 mb-4">
               <div className={`p-4 rounded-2xl ${item.priority === 'high' ? 'bg-rose-50 text-rose-600' : 'bg-orange-50 text-orange-600'}`}>
                 <Megaphone className="w-6 h-6" />
               </div>
               <div>
                  <h4 className="font-bold text-slate-800 dark:text-white text-lg leading-tight">{item.title}</h4>
                  <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">{item.date}</p>
               </div>
            </div>
