export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { RAJBARI_DATA } from './constants';

// Initialize the Gemini AI with the provided API Key
const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const db = {
  /**
   * Gemini 3 API ব্যবহার করে এআই কল করা
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    tools?: any[]; 
    responseSchema?: any;
    responseMimeType?: string;
  }) => {
    try {
      const ai = getAIClient();

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: params.contents,
        config: {
          systemInstruction: params.systemInstruction || `আপনি রাজবাড়ী জেলার একজন ভার্চুয়াল অ্যাসিস্ট্যান্ট। 
          আপনার কাজ হলো রাজবাড়ী জেলার ট্রেন ট্র্যাকিং, ডাক্তার, হাসপাতাল এবং সাধারণ তথ্য প্রদান করা।
          - সর্বদা বাংলায় উত্তর দিন।
          - গুগল সার্চ ব্যবহার করে সর্বশেষ তথ্য দিন।`,
          tools: params.tools || [{ googleSearch: {} }],
          responseSchema: params.responseSchema,
          responseMimeType: params.responseMimeType,
          temperature: 0.1,
        }
      });

      return {
        text: response.text || "",
        groundingMetadata: response.candidates?.[0]?.groundingMetadata || null
      };
    } catch (error: any) {
      console.error("Gemini API Error:", error);
      throw new Error(error.message || "এআই সার্ভিসে সংযোগ করা সম্ভব হচ্ছে না।");
    }
  },

  getCategory: async (category: string) => {
    const defaultData = (RAJBARI_DATA as any)[category] || [];
    try {
      const response = await fetch(`/api/db?category=${category}`);
      if (response.ok) {
        const serverData = await response.json();
        if (serverData && serverData.length > 0) return serverData;
      }
    } catch (e) {
      console.warn("Using offline data.");
    }
    return defaultData;
  }
};
